INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('locality-d0d1b9a2-moex-00344', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-111-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '乙公司從事先進綠色建材的研製，X5年7月1日添購一批新機器設備，成本$90,000,000。此 次資本支出，可獲得政府$30,000,000的現金補助，並於採購時直接撥款，而乙公司以現金支 付剩餘款項。該批新設備的預估耐用年限為 6 年，估計殘值為 0，折舊採直線法提列。假定 乙公司需配合政府某些永續發展政策，直到此設備的6年耐用年限結束為止。下列為乙公司 對此新設備在X5年的相關會計處理，請問何者錯誤？', '["X5年7月1日，取得新設備時，借方認列機器設備$90,000,000", "X5年7月1日，取得新設備時，貸方認列遞延政府補助利益$30,000,000與現金$60,000,000", "X5年12月31日，期末提列折舊時，借方認列折舊費用$7,500,000", "X5年12月31日，期末認列補助利益時，貸方認列政府補助利益$5,000,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:08+00:00", "source_pdf_sha1": "5ea3ac8b736e", "answer_pdf_sha1": "e04b35fd4d29", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "315", "s": "1510", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00345', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-111-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '丙公司正在評估對其營業用資產，如果採用重估價作為續後評價的模式，會對財務報表造成 什麼影響。對此丙公司選擇一筆過去曾購買的營業用土地來模擬分析，假設當時取得該土地 的所有必要成本為$30,000,000，取得該土地當年底及後續 3 個年度的重估價值分別為 $35,000,000、$28,000,000、$31,500,000、$31,000,000，下列分別敘述這四次重估價分錄中有 關損益（含其他綜合損益）的影響，何者錯誤？', '["第一次重估價，貸記其他綜合損益－重估增值$5,000,000", "第二次重估價，借記其他綜合損益－重估增值$5,000,000與重估價損失$2,000,000", "第三次重估價，貸記其他綜合損益－重估增值$1,500,000與重估價利益$2,000,000", "第四次重估價，貸記其他綜合損益－重估增值$1,000,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:08+00:00", "source_pdf_sha1": "5ea3ac8b736e", "answer_pdf_sha1": "e04b35fd4d29", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "315", "s": "1510", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00346', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-111-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '國際會計準則對於公司選擇與變更會計政策之標準，以及會計估計值變動與錯誤更正的會計 處理與揭露等有明確之規範。下列為相關的敘述，何者最為正確？', '["企業初次適用某一國際財務報導準則所產生的會計政策變動，一律需要追溯適用該變動", "會計估計值變動之影響數，僅可於變動本期認列於損益，不可於未來期間推延認列於損益", "會計錯誤的類型，只有兩種：僅在資產負債表的錯誤，及僅在綜合損益表的錯誤", "當一項會計變動無法明確區分來自會計政策變動或會計估計值變動時，該變動應視為會計 估計值變動"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:08+00:00", "source_pdf_sha1": "5ea3ac8b736e", "answer_pdf_sha1": "e04b35fd4d29", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "315", "s": "1510", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00347', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-111-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X3年的稅後淨利為$39,600，加權平均流通在外之普通股數為6,000股，所得稅率 為40%。其他相關財務資料如下：⑴X3年1月1日發行認股權，共可認購9,000股普通股， 執行價為$90，全年流通在外，且普通股全年平均股價為$150；⑵X3年1月1日以面額發行 9%之可轉換累積特別股8,000股，面額$10，1股特別股可轉換為1股普通股。該特別股全年 流通在外且無轉換；⑶X3年5月1日發行面額$600,000，票面利率6%的可轉換公司債，轉 換價格為每股$100。公司債以$660,000 發行，其中負債組成部分為$600,000（即公司債之有 效利率為6%），權益組成部分為$60,000。該公司債全年流通在外且無轉換。請問甲公司於X3 年的稀釋每股盈餘為何？', '["$5.40", "$2.25", "$3.375", "$2.50"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:08+00:00", "source_pdf_sha1": "5ea3ac8b736e", "answer_pdf_sha1": "e04b35fd4d29", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "315", "s": "1510", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00348', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-111-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '依據國際財務報導準則第15號（IFRS15），收入認列包含五項步驟：辨認客戶合約、辨認合 約中的履約義務、決定交易價格、分攤交易價格與決定收入認列時點。下列為四家公司認列 收入的會計處理，何者錯誤？', '["甲公司銷售1,000本雜誌給好心書店，於X7年3月1日收取全部款項$350,000，並將雜誌 如數送到書店。此銷售合約，提供書店享有60天內的退貨權利，但至多可退50%。如果甲 公司在3月1日無法合理預估退貨數量，則當時的銷貨收入至多認列$175,000", "乙公司銷售500罐飲料給好人商店，於X7年3月1日收取全部款項$50,000，並將飲料如 數送達商店。此銷售合約，提供商店享有90天內的退貨權利，但至多可退30%，如果乙公 司在3月1日合理估計退貨15%，則當時的銷貨收入可認列$42,500", "丙公司於X8年1月15日賒銷一批貨品$8,000給天空工廠，約定的銷貨條件為2/10、n/30， 丙公司無法認定客戶很有可能不會取得現金折扣，則丙公司應認列的銷貨收入為$7,840", "丁公司於X8年初與某賣場簽訂商品銷售合約，每個商品售價$80，如果賣場能在當年向丁 公司進貨超過5,000個，則提供數量折扣，每個商品減為$70，並於條件達成時，立即折抵 應付貨款。假定6月30日，賣場已進貨2,000個商品，則不論預估賣場在當年的進貨是否 會超過5,000個，丁公司在上半年僅可認列銷貨收入為$350,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:08+00:00", "source_pdf_sha1": "5ea3ac8b736e", "answer_pdf_sha1": "e04b35fd4d29", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "315", "s": "1510", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00349', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-111-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X1年12月15日決議辦理現金增資，並保留10,000股供員工認購，每股面額$10，認 購價格為每股$50，甲公司已於該日通知員工可認購之數量與價格，估計所給與認購新股權利於 給與日每單位公允價值為$8。若員工皆於X2年1月30日繳款截止日繳款，共計認購8,000股， 則該增資案給予員工認購對甲公司X1年及X2年財務數據影響之敘述，下列何者錯誤？', '["給予員工認購，使X1年薪資費用增加$80,000", "該增資案若募集成功，X2年薪資費用將減少$16,000", "該增資案若募集失敗，X2年薪資費用將減少$80,000", "若該增資案募集失敗，對X2年權益無影響"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:08+00:00", "source_pdf_sha1": "5ea3ac8b736e", "answer_pdf_sha1": "e04b35fd4d29", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "315", "s": "1510", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00350', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-111-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司賒銷交易提供 60 天授信期間，根據過去經驗未逾期的帳款約有 80%會於授信期間內 付款，剩餘20%約有75%會在交易後之61天至90天內付款，未於90天內付款者，則最終 僅能收回80%款項。X1年底甲公司應收帳款總帳面金額為$8,000,000，其帳齡為： 帳齡 60天以內 61天至90天 91天以上 總帳面金額 $6,500,000 $1,000,000 $500,000 若X1年底調整前備抵損失為借餘$50,000，則X1年底該應收帳款之攤銷後成本為何？', '["$7,735,000", "$7,785,000", "$7,835,000", "$7,900,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:08+00:00", "source_pdf_sha1": "5ea3ac8b736e", "answer_pdf_sha1": "e04b35fd4d29", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "315", "s": "1510", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00351', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-111-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X1年初支付$2,000交易成本，以每股$50購入乙公司10,000股普通股，X1年底乙 公司股票每股公允價值為$58。甲公司於X2年底以每股$70將該投資全數售出。甲公司於原 始認列時未將該投資指定為透過其他綜合損益按公允價值衡量，其 X1 年及 X2 年列報之稅 前淨利均為$500,000，若於原始認列時將該投資指定為透過其他綜合損益按公允價值衡量， 則甲公司X1年及X2年之稅前淨利應分別為何？', '["$420,000及$380,000", "$420,000及$580,000", "$422,000及$380,000", "$422,000及$580,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:08+00:00", "source_pdf_sha1": "5ea3ac8b736e", "answer_pdf_sha1": "e04b35fd4d29", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "315", "s": "1510", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00352', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-111-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司於今年3月1日開始設置零用金，便於管控日常小額現金支出。初始設定的零用金額 度為$8,000，並於3月間有以下3筆交易：3月8日支付節日賀卡費用$600、3月15日支付 郵資$500與3月27日支付辦公用品一批$1,200。3月31日進行零用金撥補，當時盤點現金 餘額為$5,850，後於4月1日調整零用金額度為$6,000。下列有關零用金的分錄，何者錯誤？', '["3月1日，借：零用金$8,000；貸：銀行存款$8,000", "3月31日，撥補時，貸方的銀行存款金額為$2,150", "3月31日，撥補時，貸方除了銀行存款外，另需貸：現金短溢$150", "4月1日，調整零用金額度時，貸方為銀行存款$2,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:08+00:00", "source_pdf_sha1": "5ea3ac8b736e", "answer_pdf_sha1": "e04b35fd4d29", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "315", "s": "1510", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00353', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-111-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司X1年7月31日及8月31日未兌現支票金額分別為$68,000及$90,000，其中包含銀 行已保付支票，金額分別為$20,000 及$30,000。若甲公司 X1 年 8 月份開立支票金額為 $675,000，則X1年8月份銀行對帳單之支票支出金額為何？', '["$643,000", "$653,000", "$687,000", "$697,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:08+00:00", "source_pdf_sha1": "5ea3ac8b736e", "answer_pdf_sha1": "e04b35fd4d29", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "315", "s": "1510", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL)
